request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelId ?modelName ?org WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:normalizedId ?modelId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model bbo:id ?bboId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . }
  FILTER(CONTAINS(LCASE(STR(?modelId)), "1f1b01e0a85340689b6df314b32bb4b6") || 
         CONTAINS(LCASE(STR(?origId)), "1f1b01e0a85340689b6df314b32bb4b6") ||
         CONTAINS(LCASE(STR(?bboId)), "1f1b01e0a85340689b6df314b32bb4b6"))
}
LIMIT 25
